import{_ as i}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as e,c as l,e as a}from"./app.f6447a9f.js";const n={},d=a(`<h3 id="浏览器内核" tabindex="-1"><a class="header-anchor" href="#浏览器内核" aria-hidden="true">#</a> 浏览器内核</h3><p>渲染引擎，负责对网页语法的解释并渲染网页</p><p>Chrome内核：webkeit--》Blink</p><h3 id="doctype作用" tabindex="-1"><a class="header-anchor" href="#doctype作用" aria-hidden="true">#</a> DOCTYPE作用</h3><p>声明文件类型定义，告诉浏览器应该按那个规范解析文档</p><p>严格模式：按W3C标准解析</p><p>混合模式：兼容模式，按浏览器自己的方式解析</p><h3 id="页面三层构成" tabindex="-1"><a class="header-anchor" href="#页面三层构成" aria-hidden="true">#</a> 页面三层构成</h3><p>结构层：HTML，实现页面结构</p><p>表示层：CSS，完成页面的表现和风格</p><p>行为层：Javascript实现客户端的交互功能</p><h3 id="web标准与w3c" tabindex="-1"><a class="header-anchor" href="#web标准与w3c" aria-hidden="true">#</a> Web标准与W3C</h3><p>web标准：将三部分独立分开，使其更具有模块化</p><p>W3C：对web标准提出规范化要求</p><ul><li>html，标签字母小写，标签闭合，不允许随意嵌套</li><li>js、css：尽量少用行内样式，尽量使用外链样式和脚本</li></ul><h3 id="url到页面渲染" tabindex="-1"><a class="header-anchor" href="#url到页面渲染" aria-hidden="true">#</a> URL到页面渲染</h3><ul><li>域名解析，浏览器根据DNS服务器得到域名IP地址</li><li>发起TCP三次握手</li><li>建立TCP连接后向服务器发起HTTP请求</li><li>服务器接处理HTTP请求，返回HTML代码</li><li>浏览器解析HTML代码，渲染页面</li></ul><h3 id="回流重绘" tabindex="-1"><a class="header-anchor" href="#回流重绘" aria-hidden="true">#</a> 回流重绘</h3><p>首先了解浏览器得渲染过程，渲染引擎会解析HTMl文档构建DOM树，与此同时渲染引擎使用CSS解析器解析CSS文档构建CSSOM树。接下来将两棵树关联起来形成渲染树。然后浏览器按照渲染树进行布局（回流）计算得到节点得几何信息（位置，大小），根据渲染树以及回流得到的几何信息得到节点得绝对像素（重绘），最后将像素发给GPU，展示在页面上</p><p>何时会发生回流</p><ul><li>添加、删除可见DOM元素</li><li>元素位置发生变化</li><li>元素尺寸发生变化</li><li>内容发生变化</li><li>浏览器窗口尺寸发生变化</li><li>页面首次渲染时</li></ul><p>回流一定会引起重绘，重绘不一定引起回流</p><p>何时发生重绘</p><ul><li>改变背景颜色</li><li>改变文字颜色</li><li>改变边框颜色</li></ul><p>减少回流重绘方法</p><ul><li>visibility代替display:none,因为前者只会触发一次重绘，后者触发回流</li><li>避免使用表格布局</li><li>避免频繁操作DOM，操作DOM时拷贝原始节点，使其脱离文档流（display:none）再进行修改(display:block)，最后替换原始元素</li><li>避免频繁读取引起回流重绘的属性（类似offsetWidth），可以将其用变量保存起来</li><li>现代浏览器大多都是通过队列机制来批量更新布局，浏览器会把修改操作放在队列中，至少一个浏览器刷新（即16.6ms）才会清空队列，但当你获取布局信息的时候，队列中可能有会影响这些属性或方法返回值的操作，即使没有，浏览器也会强制清空队列，触发回流与重绘来确保返回正确的值。</li></ul><h3 id="同源跨域" tabindex="-1"><a class="header-anchor" href="#同源跨域" aria-hidden="true">#</a> 同源跨域</h3><p>原理</p><p>跨域是指浏览器不能执行其他网站的脚本。它是浏览器同源策略造成的，是浏览器对JS实施的安全限制。协议、端口、域名、任何一个不同则为不同源，不同源之间无法访问。</p><p>解决</p><ul><li>JSONP：动态创建script，请求带参网址实现跨域，缺点是只支持get方法，需要后端配合返回指定格式的数据</li><li>CORS：服务端设置Access-Control-Allow-Origin</li><li>代理跨域：启动代理服务器</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>一.cross(html5支持)
后台设置 header(&#39;Access-Control-Allow-Origin:*&#39;);

//有时候也需要添加以下设置
header(&quot;Access-Control-Allow-Headers: Origin, X-Requested-With, Content-Type, Accept&quot;);
header(&#39;Access-Control-Allow-Methods: GET, POST, PUT&#39;);

二、.JSNOP
1. &lt;script src=&quot;xxxx.xxx?callback=callbackname&quot;&gt;&lt;/script&gt;
原理：利用script的src属性支持跨域访问
	  写上需要请求的页面，拼接方法名，发送服务器
	  服务器将数据作为方法名的参数(字符串拼接)，返回浏览器
	  浏览器将返回的方法名(data)作为js解析
	  
2. dataType:JSONP,会自动在请求url后拼接?&#39;callback=xxx&#39;,在生成的回调函数中将数据返回，供success使用
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="浏览器存储" tabindex="-1"><a class="header-anchor" href="#浏览器存储" aria-hidden="true">#</a> 浏览器存储</h3><ul><li>请求携带</li><li><ul><li>cookie数据始终在同源http请求中携带</li><li>WebStorage不会自动将数据发送给服务器</li></ul></li><li>存储大小</li><li><ul><li>cookie：4k；webstorage：5M</li></ul></li><li>有效时间</li><li><ul><li>localStorage，永久存储鱼浏览器除非手动删除</li><li>sessionStorage，数据在当前浏览器窗口关闭之后自动删除</li><li>cookie在过期时间之内有效</li></ul></li></ul><h3 id="viewport" tabindex="-1"><a class="header-anchor" href="#viewport" aria-hidden="true">#</a> viewport</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width,initial-scale=1.0,minimu
 // width 设置viewport宽度，为⼀个正整数，或字符串‘device-width’
 // device-width 设备宽度
 // height 设置viewport⾼度，⼀般设置了宽度，会⾃动解析出⾼度，可以不⽤设置
 // initial-scale 默认缩放⽐例（初始缩放⽐例），为⼀个数字，可以带⼩数
 // minimum-scale 允许⽤户最⼩缩放⽐例，为⼀个数字，可以带⼩数
 // maximum-scale 允许⽤户最⼤缩放⽐例，为⼀个数字，可以带⼩数
 // user-scalable 是否允许⼿动缩放
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如何处理移动端1px渲染未2px</p><ul><li>mate 标签中的 viewport 属性 ， initial-scale 设置为</li><li>rem 按照设计稿标准⾛，外加利⽤ transfrome 的 scale(0.5) 缩⼩⼀倍即可；</li></ul><h3 id="增强降级" tabindex="-1"><a class="header-anchor" href="#增强降级" aria-hidden="true">#</a> 增强降级</h3><ul><li><p>渐进增强：针对低版本浏览器进⾏构建⻚⾯，保证最基本的功能，然后再针对⾼级浏览器 进⾏效果、交互等改进和追加功能达到更好的⽤户体验。</p></li><li><p>优雅降级：⼀开始就构建完整的功能，然后再针对低版本浏览器进⾏兼容。</p></li></ul>`,40),s=[d];function r(t,c){return e(),l("div",null,s)}const h=i(n,[["render",r],["__file","Brower.html.vue"]]);export{h as default};
